import 'dart:convert';
import 'package:http/http.dart' as http;

Future<Map<String, dynamic>> fetchUser(String url) async {
  final res = await http.get(Uri.parse(url));
  final data = jsonDecode(res.body);
  return {'id': data['id']};
}
